import React from 'react';
import { View, WebView } from 'react-native';
import Constants from 'expo-constants';

const messageHandler = (eventName, data) => {
  const event = new MessageEvent(eventName, { data });
  window.dispatchEvent(event);
};

const messagingInterop = {
  postMessage: messageHandler,
};

const webviewMessageHandler = message => {
  if (message && message.origin === 'js-interop') {
    const data = JSON.parse(message.data);
    messagingInterop[data.eventName](data.data);
  }
};

const HTML = `
  <html>
    <body>
      <!-- Your mobile website here -->
      <script>
        window.__REACT_NATIVE_WEBVIEW__ = { postMessage: messagingInterop.postMessage };
        window.addEventListener('message', webviewMessageHandler);
      </script>
    </body>
  </html>
`;

export default function WebViewComponent() {
  return (
    <View style={{ flex: 1 }}>
      <WebView
        source={{ html: HTML }}
        javaScriptEnabled={true}
        domStorageEnabled={true}
        originWhitelist={['*']}
        startsWithClientScript={true}
        injectedJavaScript={`
          // Custom JavaScript for accessing native features
          // Example: navigator.geolocation.getCurrentPosition(...)
        `}
      />
    </View>
  );
}